1	type Item = { type: string };
2	type Scenario = {
3	  steps: Array<{ op: string; items?: Item[] }>;
4	};
5	
6	const PROCESSING_FEE = 5;
7	const BASE_PREMIUM_BY_ITEM_TYPE: Record<string, number> = {
8	  sword: 100,
9	  amulet: 60,
10	  staff: 80,
11	  potion: 40,
12	  rune: 25,
13	  moonstone: 25,
14	};
15	const RUNE_BLOCK_OF_3_PRICE = 60;
16	
17	function quotePremium(items: Item[]): number {
18	  const countsByType: Record<string, number> = {};
19	  for (const item of items) {
20	    countsByType[item.type] = (countsByType[item.type] ?? 0) + 1;
21	  }
22	  let policyBase = 0;
23	  for (const [type, count] of Object.entries(countsByType)) {
24	    if (type === "rune" && count === 3) {
25	      policyBase += RUNE_BLOCK_OF_3_PRICE;
26	    } else {
27	      policyBase += count * BASE_PREMIUM_BY_ITEM_TYPE[type];
28	    }
29	  }
30	  const firstInsurance = policyBase / 10;
31	  return Math.ceil(policyBase + firstInsurance) + PROCESSING_FEE;
32	}
33	
34	export function processScenario(scenario: unknown): unknown {
35	  const { steps } = scenario as Scenario;
36	  const results = steps.map((step) => ({
37	    premium: quotePremium(step.items ?? []),
38	  }));
39	  return { results };
40	}
